", "start": "11:00"}, {"end": "16:30", "start": "16:00"}], "enabled": true}}', 0, true, '[{"id": "ff1", "type": "text", "label": "Name", "mapTo": "name", "enabled": true, "required": true, "placeholder": "Your name"}, {"id": "ff2", "type": "email", "label": "Email", "mapTo": "email", "enabled": true, "required": true, "placeholder": "your@email.com"}, {"id": "ff3", "type": "phone", "label": "Phone", "mapTo": "phone", "enabled": true, "required": true, "placeholder": "+91 98765 43210"}, {"id": "ff-1777367333210", "type": "text", "label": "Age", "mapTo": "age", "enabled": true, "required": true, "placeholder": ""}]', 0, '2026-04-28 11:51:14.229325+05:30', '2026-04-28 14:38:58.3775+05:30', '{}', NULL, 'https://digygo.com/', NULL, NULL, 1, 0, 'days', 1, false);
